changeSet.sql:
DELETE FROM character_class_levels ccl
 WHERE ccl.class_id IS NOT NULL
   AND NOT EXISTS (SELECT 1 FROM character_class cc WHERE cc.class_id = ccl.class_id);

DELETE FROM character_skill_proficiencies csp
 WHERE csp.skill_id IS NOT NULL
   AND NOT EXISTS (SELECT 1 FROM skill s WHERE s.skill_id = csp.skill_id);

DELETE FROM character_stats cs
 WHERE cs.stat_type_id IS NOT NULL
   AND NOT EXISTS (SELECT 1 FROM ability_score a WHERE a.ability_score_id = cs.stat_type_id);

DELETE FROM character_wallets cw
 WHERE cw.currency_type_id IS NOT NULL
   AND NOT EXISTS (SELECT 1 FROM currency c WHERE c.currency_id = cw.currency_type_id);

DELETE FROM wallet_transactions wt
 WHERE wt.currency_type_id IS NOT NULL
   AND NOT EXISTS (SELECT 1 FROM currency c WHERE c.currency_id = wt.currency_type_id);

DELETE FROM character_known_spells cks
 WHERE cks.spell_id IS NOT NULL
   AND NOT EXISTS (SELECT 1 FROM spell sp WHERE sp.spell_id = cks.spell_id);

UPDATE characters ch
   SET background_id = NULL
 WHERE ch.background_id IS NOT NULL
   AND NOT EXISTS (SELECT 1 FROM background b WHERE b.background_id = ch.background_id);
